// Normalisiert + sanitisiert die eingehende Mail vor dem LLM-Call.
// Schützt vor Prompt-Injection und kappt Längen.
const MAX_SUBJECT = 250;
const MAX_BODY = 6000;

function clean(str) {
  if (!str) return '';
  return String(str)
    // Steuer-/Markdown-Zeichen entschärfen, die als Prompt-Steuerung missbraucht werden könnten
    .replace(/[\u0000-\u001F\u007F]/g, ' ')
    .replace(/`{3,}/g, "'''")
    .trim();
}

const item = $input.first().json;
const config = $('Set: Triage-Konfiguration').first().json;

const subject = clean(item.subject).slice(0, MAX_SUBJECT);
const from = clean(item.from || item.fromEmail || (item.headers && item.headers.from) || '');
// 'simple'-Format legt Text in textPlain / textHtml ab
let body = item.textPlain || item.text || item.textHtml || item.html || '';
body = clean(body).slice(0, MAX_BODY);

const senderEmailMatch = from.match(/[\w.+-]+@[\w-]+\.[\w.-]+/);
const senderEmail = senderEmailMatch ? senderEmailMatch[0] : '';

return [{
  json: {
    subject,
    from,
    senderEmail,
    body,
    receivedAt: item.date || new Date().toISOString(),
    messageId: item.messageId || (item.headers && item.headers['message-id']) || '',
    config
  }
}];

// Merged LLM-Output mit der Original-Mail + Config und leitet das Routing-Ziel ab.
const llm = $input.first().json;
const mail = $('Code: Mail normalisieren + sanitisieren').first().json;
const config = mail.config;

// chainLlm legt das geparste Objekt je nach Version in .output oder direkt ab
const c = llm.output || llm;

const category = ['billing','technical','sales','general'].includes(c.category) ? c.category : 'general';
const priority = ['urgent','high','normal','low'].includes(c.priority) ? c.priority : 'normal';
const team = config.teams[category] || config.teams.general;

const slaHours = priority === 'urgent' ? config.slaHoursUrgent : (priority === 'high' ? 8 : 24);
const slaDeadline = new Date(Date.now() + slaHours * 3600 * 1000).toISOString();

return [{
  json: {
    subject: mail.subject,
    from: mail.from,
    senderEmail: mail.senderEmail,
    body: mail.body,
    messageId: mail.messageId,
    receivedAt: mail.receivedAt,
    category,
    priority,
    sentiment: c.sentiment || 'neutral',
    language: c.language || 'de',
    summary: c.summary || '',
    suggestedReply: c.suggested_reply || '',
    needsHuman: c.needs_human === true,
    reasoning: c.reasoning || '',
    teamLabel: team.label,
    teamEmail: team.email,
    teamSlack: team.slack,
    slaHours,
    slaDeadline,
    config
  }
}];

// Zentraler Error-Sammler. Empfaengt Items aus dem Error-Output des LLM-Nodes
// und aus fehlgeschlagenen Send-/HTTP-Nodes. Schreibt eine maschinenlesbare
// Fehlerzeile fuer Alerting / DLQ (Dead-Letter-Queue).
const items = $input.all();
return items.map((it) => ({
  json: {
    triageStatus: 'FAILED',
    failedAt: new Date().toISOString(),
    error: it.json.error || it.error || 'unknown_error',
    subject: it.json.subject || (it.json.config ? '' : it.json.subject) || '',
    senderEmail: it.json.senderEmail || '',
    messageId: it.json.messageId || '',
    note: 'Mail konnte nicht automatisch triagiert werden — manuelle Bearbeitung noetig.'
  }
}));

